// Real nickname lookup needs a live call to the game's official/third-party
// "check role" endpoint through a backend (can't be faked reliably offline).
// This preview only validates the ID's format so it never shows a wrong name.
function verifyGameIdFormat(gameId) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      if (!gameId || gameId.length < 6 || !/^\d+$/.test(gameId)) {
        reject(new Error("Game ID ပုံစံ မှားနေပါသည်"));
      } else {
        resolve(true);
      }
    }, 700);
  });
}

function fmt(n) {
  return (n ?? 0).toLocaleString("en-US");
}

// Applies a reseller's flat discount to a price, rounding to the nearest
// whole unit (MMK/THB don't use decimals here). `percent` is 0 for regular
// users, so this is a no-op unless the logged-in user is a reseller.
function applyResellerDiscount(price, percent) {
  if (!percent) return price;
  return Math.round(price * (1 - percent / 100));
}

// Clipboard helper with a manual-copy fallback for sandboxed environments
// where navigator.clipboard may be blocked.
function copyText(text, onDone) {
  const fallback = () => {
    try {
      const ta = document.createElement("textarea");
      ta.value = text;
      ta.style.position = "fixed";
      ta.style.opacity = "0";
      document.body.appendChild(ta);
      ta.focus();
      ta.select();
      document.execCommand("copy");
      document.body.removeChild(ta);
      onDone(true);
    } catch (e) {
      onDone(false);
    }
  };
  if (navigator.clipboard && navigator.clipboard.writeText) {
    navigator.clipboard.writeText(text).then(() => onDone(true)).catch(fallback);
  } else {
    fallback();
  }
}

// ---------- Small UI atoms ----------
function TopBar({ title, onBack }) {
  return (
    <div className="sticky top-0 z-20 bg-gradient-to-b from-slate-900 to-slate-800 text-white px-4 py-3 relative flex items-center justify-center shadow-md">
      {onBack && (
        <button onClick={onBack} className="absolute left-4 text-violet-300 text-sm font-medium active:opacity-60">
          ← Back
        </button>
      )}
      <div className="font-extrabold text-lg tracking-wide bg-gradient-to-r from-amber-200 via-yellow-100 to-amber-300 bg-clip-text text-transparent drop-shadow-sm">
        {title}
      </div>
    </div>
  );
}

function BottomNav({ active, onNavigate, unreadCount = 0, isAdmin = false, pendingCount = 0 }) {
  const items = [
    { key: "shop", label: "Home", icon: "🏠" },
    { key: "message", label: "MESSAGE", icon: "📄" },
    { key: "spin", label: "ကံစမ်းမဲ", icon: "🎡" },
    { key: "profile", label: "PROFILE", icon: "👤" },
    ...(isAdmin ? [{ key: "approve", label: "အတည်ပြုရန်", icon: "✅" }] : []),
    ...(isAdmin ? [{ key: "admin", label: "ADMIN", icon: "🛠️" }] : []),
  ];
  return (
    <div
      className="sticky bottom-0 z-20 bg-slate-950 grid text-[11px] text-slate-400 border-t border-slate-800"
      style={{ gridTemplateColumns: `repeat(${items.length}, minmax(0, 1fr))` }}
    >
      {items.map((it) => (
        <button
          key={it.key}
          onClick={() => onNavigate && onNavigate(it.key)}
          className={`relative flex flex-col items-center gap-1 py-2 ${active === it.key ? "text-violet-400" : ""}`}
        >
          <span className="relative text-lg leading-none">
            {it.icon}
            {it.key === "message" && unreadCount > 0 && (
              <span className="absolute -top-1.5 -right-2.5 bg-rose-500 text-white text-[9px] font-bold rounded-full min-w-[15px] h-[15px] px-1 flex items-center justify-center">
                {unreadCount}
              </span>
            )}
            {it.key === "approve" && pendingCount > 0 && (
              <span className="absolute -top-1.5 -right-2.5 bg-rose-500 text-white text-[9px] font-bold rounded-full min-w-[15px] h-[15px] px-1 flex items-center justify-center">
                {pendingCount}
              </span>
            )}
          </span>
          {it.label}
        </button>
      ))}
    </div>
  );
}

function Pill({ children, tone = "slate" }) {
  const tones = {
    slate: "bg-slate-700 text-slate-100",
    green: "bg-emerald-500 text-white",
    amber: "bg-amber-500 text-white",
    red: "bg-rose-500 text-white",
  };
  return <span className={`px-3 py-1 rounded-full text-xs font-semibold ${tones[tone]}`}>{children}</span>;
}

