  async function handleBroadcastFilePick(file) {
    setBroadcastFile(file);
    setBroadcastImageUrl(null);
    if (!file) return;
    setBroadcastUploading(true);
    try {
      const url = await uploadImage(file);
      setBroadcastImageUrl(url);
    } catch (err) {
      showToast({ type: "error", msg: "ပုံတင်ခြင်း မအောင်မြင်ပါ" });
    } finally {
      setBroadcastUploading(false);
    }
  }

  async function handleBroadcastSend() {
    const text = broadcastText.trim();
    if ((!text && !broadcastImageUrl) || broadcastSending || broadcastUploading) return;
    setBroadcastSending(true);
    try {
      const result = await api.broadcastMessage(telegramId, text, broadcastImageUrl);
      showToast({ type: "ok", msg: `User ${result.sent || 0} ဦးထံသို့ ပို့ပြီးပါပြီ` });
      setBroadcastText("");
      setBroadcastFile(null);
      setBroadcastImageUrl(null);
    } catch (err) {
      showToast({ type: "error", msg: "ပို့ခြင်း မအောင်မြင်ပါ — ပြန်စမ်းကြည့်ပါ" });
    } finally {
      setBroadcastSending(false);
    }
  }
  async function handleSetReseller(isReseller) {
    const targetId = resellerTargetId.trim();
    if (!targetId || resellerSaving) return;
    setResellerSaving(true);
    try {
      await api.setReseller(telegramId, targetId, isReseller);
      showToast({
        type: "ok",
        msg: isReseller ? `Telegram ID ${targetId} ကို Reseller ဖြစ်စေပြီးပါပြီ` : `Telegram ID ${targetId} ရဲ့ Reseller status ကို ဖြုတ်လိုက်ပါပြီ`,
      });
      setResellerTargetId("");
    } catch (err) {
      showToast({ type: "error", msg: err.message === "User not found — they need to have opened the app at least once" ? "ဒီ Telegram ID က app ကို တစ်ခါမှ မဖွင့်ဖူးသေးပါ" : "လုပ်ဆောင်ခြင်း မအောင်မြင်ပါ" });
    } finally {
      setResellerSaving(false);
    }
  }
  async function handleAdjustBalance() {
    const targetId = adjustTargetId.trim();
    const amt = Number(adjustAmount);
    if (!targetId || !amt || adjustSaving) return;
    setAdjustSaving(true);
    try {
      const result = await api.adjustBalance(telegramId, targetId, adjustCurrency, amt, adjustReason.trim());
      showToast({
        type: "ok",
        msg: `Telegram ID ${targetId} ရဲ့ balance အသစ်: ${fmt(result.newBalance)} ${adjustCurrency.toUpperCase()}`,
      });
      setAdjustTargetId("");
      setAdjustAmount("");
      setAdjustReason("");
    } catch (err) {
      showToast({ type: "error", msg: err.message || "လုပ်ဆောင်ခြင်း မအောင်မြင်ပါ" });
    } finally {
      setAdjustSaving(false);
    }
  }

